// GET /api/posts?limit=20&after=<cursor>

const MAX_LIMIT = 100;

/**
 * Encode a compound cursor (created_at, id) as an opaque base64 JSON string.
 */
function encodeCursor(row) {
    const payload = {
        // Use ISO string so the timestamp round-trips with full precision.
        createdAt: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64url');
}

/**
 * Decode an opaque cursor back into { createdAt, id }.
 * Throws on anything malformed so the caller can return a 400.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        decoded = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }

    // Validate shape — never trust the client.
    if (
        !decoded ||
        typeof decoded !== 'object' ||
        typeof decoded.createdAt !== 'string' ||
        decoded.id === undefined ||
        decoded.id === null
    ) {
        throw new Error('Invalid cursor payload');
    }

    const createdAt = new Date(decoded.createdAt);
    if (Number.isNaN(createdAt.getTime())) {
        throw new Error('Invalid cursor timestamp');
    }

    return { createdAt: decoded.createdAt, id: decoded.id };
}

async function getPosts(req, res) {
    // Clamp limit to a sane range.
    let limit = parseInt(req.query.limit, 10) || 20;
    if (limit < 1) limit = 1;
    if (limit > MAX_LIMIT) limit = MAX_LIMIT;

    // Decode the cursor up front so we can fail fast with a 400.
    let cursor = null;
    if (req.query.after !== undefined && req.query.after !== '') {
        try {
            cursor = decodeCursor(req.query.after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid pagination cursor' });
        }
    }

    // Fetch limit + 1 rows to detect whether another page exists (N+1 trick).
    const fetchCount = limit + 1;

    let result;
    if (cursor) {
        // Compound keyset condition matching ORDER BY created_at DESC, id DESC.
        // Row tuples are strictly "less than" the cursor in the sort order:
        //   created_at < cursor.created_at
        //   OR (created_at = cursor.created_at AND id < cursor.id)
        // Postgres row-value comparison expresses this cleanly.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1, $2)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.createdAt, cursor.id, fetchCount]
        );
    } else {
        // First page — no cursor filter.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [fetchCount]
        );
    }

    const rows = result.rows;
    const hasMore = rows.length > limit;

    // Drop the sentinel extra row before returning.
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor =
        hasMore && posts.length > 0
            ? encodeCursor(posts[posts.length - 1])
            : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Key implementation notes

- **Row-value comparison `(created_at, id) < ($1, $2)`** is the heart of the conversion. Postgres evaluates tuple comparison lexicographically, which is exactly the keyset condition for `ORDER BY created_at DESC, id DESC`. The `id` tiebreaker guarantees a total ordering even when many posts share a `created_at`, so no row is skipped or duplicated across pages.
- **`base64url`** avoids `+`, `/`, and `=` characters that need URL-encoding in a query string. (Plain `base64` also works but should be URL-encoded by the client.)
- **N+1 trick**: we request `limit + 1`, and the presence of that extra row tells us `hasMore` without a second query. The extra row is sliced off before responding.
- **Validation**: `decodeCursor` throws on bad base64, bad JSON, wrong shape, or an unparseable timestamp — all funneled to a single `400`.
- **Index**: for this to be fast, ensure a composite index matching the sort exists, e.g. `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;`

## Why cursor-based pagination is superior here

1. **Consistent performance at scale.** `OFFSET 1000000` forces Postgres to scan and discard a million rows on every request — cost grows linearly with page depth. A keyset `WHERE (created_at, id) < (...)` seeks directly into the index and reads only `limit + 1` rows, so page 1 and page 50,000 cost the same.
2. **No skipped or duplicated rows under writes.** With offset pagination, if a new post is inserted (or one deleted) between page loads, every subsequent row shifts by one — users see a duplicate or miss an item. A cursor pins an absolute position in the sort order, so concurrent inserts/deletes don't corrupt the sequence. This matters for a `created_at DESC` feed where new content arrives at the top constantly.
3. **Dropping `COUNT(*)` removes an expensive full scan.** On large tables `COUNT(*)` with a filter can't be answered from an index alone and gets slower as the table grows — and the total/`totalPages` it produced was both costly and stale by the next request.

The main trade-off: you lose random access to arbitrary page numbers (no "jump to page 500"). For an infinite-scroll or "load more" feed sorted by recency, that's not a feature users need — making cursor pagination the right fit.

