// ─── Cursor Helpers ───────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque base64 cursor string.
 * @param {string|Date} createdAt
 * @param {number|string} id
 * @returns {string}
 */
function encodeCursor(createdAt, id) {
    const payload = JSON.stringify({
        created_at: new Date(createdAt).toISOString(),
        id: String(id),
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

/**
 * Decodes a base64 cursor string back into { created_at, id }.
 * Returns null if the cursor is missing/null (first-page case).
 * Throws a TypeError with a descriptive message for malformed cursors.
 * @param {string|undefined} cursor
 * @returns {{ created_at: string, id: string } | null}
 */
function decodeCursor(cursor) {
    if (!cursor) return null;

    let parsed;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        parsed = JSON.parse(json);
    } catch {
        throw new TypeError('Cursor is not valid base64-encoded JSON.');
    }

    // Validate shape
    if (
        typeof parsed !== 'object' ||
        parsed === null ||
        !parsed.created_at ||
        !parsed.id ||
        isNaN(Date.parse(parsed.created_at))
    ) {
        throw new TypeError('Cursor payload is missing required fields (created_at, id).');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

// ─── Route Handler ────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // --- Parse & validate query params ---
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);

    let cursor;
    try {
        cursor = decodeCursor(req.query.after); // null on first page
    } catch (err) {
        return res.status(400).json({
            error: 'Invalid cursor.',
            detail: err.message,
        });
    }

    // --- Build query ---
    // Use the LIMIT N+1 trick: fetching one extra row tells us whether
    // another page exists without a separate COUNT(*) query.
    const fetchLimit = limit + 1;

    let result;

    if (cursor === null) {
        // ── First page: no cursor filter ──────────────────────────────────────
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
             FROM   posts
             WHERE  published = true
             ORDER  BY created_at DESC, id DESC
             LIMIT  $1`,
            [fetchLimit]
        );
    } else {
        // ── Subsequent pages: seek past the cursor ────────────────────────────
        //
        // Sorting is (created_at DESC, id DESC), so "after the cursor" means:
        //   created_at is strictly older  →  created_at < cursor.created_at
        //   OR same timestamp but smaller id  →  created_at = cursor.created_at AND id < cursor.id
        //
        // This is the "keyset" / "seek" predicate — it replaces OFFSET entirely
        // and remains O(log N) via the index on (created_at DESC, id DESC).
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
             FROM   posts
             WHERE  published = true
               AND  (
                        created_at < $1
                     OR (created_at = $1 AND id < $2)
                    )
             ORDER  BY created_at DESC, id DESC
             LIMIT  $3`,
            [cursor.created_at, cursor.id, fetchLimit]
        );
    }

    // --- Determine hasMore & trim to requested limit ---
    const hasMore = result.rows.length > limit;
    const posts   = hasMore ? result.rows.slice(0, limit) : result.rows;

    // --- Build next cursor from the last row in the returned page ---
    let nextCursor = null;
    if (hasMore && posts.length > 0) {
        const last = posts[posts.length - 1];
        nextCursor = encodeCursor(last.created_at, last.id);
    }

    // --- Respond ---
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,  // null when this is the last page
            limit,
        },
    });
}
```

---

## Why cursor-based pagination is superior here

| Concern | Offset-based | Cursor-based |
|---|---|---|
| **Performance at scale** | `OFFSET N` makes PostgreSQL scan and discard N rows on every request — O(N) cost that grows with page depth | The `WHERE (created_at, id) < ($1, $2)` seek predicate jumps straight to the right position via the index — O(log N) always |
| **Consistency under writes** | If a row is inserted or deleted between page requests, rows shift and you get duplicates or skipped rows | The cursor is anchored to a specific row, so new inserts/deletes don't disturb the window |
| **No expensive COUNT(*)** | Requires a full-table `COUNT(*)` to report `totalPages` | Eliminated entirely; `hasMore` is derived for free from the N+1 trick |
| **Infinite scroll / real-time feeds** | Breaks badly — late-arriving posts cause the "you missed it" problem | Handles live feeds naturally; the cursor is a stable bookmark |

The trade-off is that cursor-based pagination doesn't support **jumping to an arbitrary page** (e.g. "go to page 47"). If random-access page jumping is a product requirement, that's when a hybrid approach (cursor for feed-style browsing, a separate search endpoint with OFFSET for admin/filtered views) is worth considering. For a public post feed like this one, cursor-based is the right default.

